__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, int Size, int t)
{   
    int idx = get_global_id(0);
    if(idx >= Size-1-t) return;

    int row = idx + t + 1;
    int col = t;

    float divisor = a_cuda[Size * t + t];
    float numerator = a_cuda[Size * row + col];

    m_cuda[Size * row + col] = numerator / divisor;
}

__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, int Size, int j1, int t)
{
    int xidx = get_global_id(0);
    int yidx = get_global_id(1);

    if(xidx >= Size-1-t) return;
    if(yidx >= Size-t) return;

    int row_a = xidx + 1 + t;
    int col_a = yidx + t;

    int m_idx = Size * row_a + t;
    int a_pivot_idx = Size * t + col_a;
    int a_target_idx = Size * row_a + col_a;

    float m_val = m_cuda[m_idx];
    float a_pivot_val = a_cuda[a_pivot_idx];

    a_cuda[a_target_idx] -= m_val * a_pivot_val;

    if(yidx == 0){
        int b_idx = row_a;
        float b_pivot_val = b_cuda[t];
        b_cuda[b_idx] -= m_val * b_pivot_val;
    }
}
